"""Instruction-gated citation planning over a retained, unmodified corpus."""
from __future__ import annotations

from dataclasses import dataclass, field
import logging
import re
from typing import Any, Mapping, Sequence
from urllib.parse import urlsplit

from src.polaris_graph.settings import resolve
from src.polaris_graph.retrieval.rq_eligibility import (
    _admitted_genres,
    _parse_recency_bounds,
    _row_genre,
    _row_language,
    _row_year,
    detect_language_offline,
)
from src.polaris_graph.retrieval.document_type_classifier import DocumentType

_OFF = frozenset({"", "0", "false", "no", "off", "disabled"})
logger = logging.getLogger("polaris_graph.exclusive_citation_eligibility")
_EXCLUSIVE_RE = re.compile(
    r"\b(?:only|exclusively|restricted\s+to|limited\s+to|must\s+(?:all\s+)?be|do\s+not\s+(?:use|cite))\b",
    re.IGNORECASE,
)

# These are publication-surface classes, not journal-name allowlists.  They are deliberately
# conservative: a known repository/working-paper/news/blog surface vetoes every positive signal.
_PREPRINT_OR_WORKING_PAPER_HOSTS = frozenset({
    "arxiv.org", "ssrn.com", "nber.org", "preprints.org", "researchsquare.com",
    "biorxiv.org", "medrxiv.org", "osf.io", "psyarxiv.com", "researchgate.net",
    "academia.edu",
})
_NON_JOURNAL_HOSTS = _PREPRINT_OR_WORKING_PAPER_HOSTS | frozenset({
    "medium.com", "substack.com", "wordpress.com", "blogspot.com",
})
_NON_JOURNAL_DOI_REGISTRANTS = frozenset({
    "10.1101",   # bioRxiv / medRxiv
    "10.1109",   # mixed IEEE journal/conference registrant; DOI alone is ambiguous
    "10.1145",   # ACM proceedings-heavy registrant
    "10.17605",  # OSF
    "10.2139",   # SSRN
    "10.3386",   # NBER working papers
    "10.48550",  # arXiv
    "10.5061",   # Dryad datasets
    "10.5281",   # Zenodo repository records
    "10.6084",   # Figshare repository records
    "10.7910",   # Dataverse datasets
})
_NON_JOURNAL_TEXT_RE = re.compile(
    r"\b(?:pre[ -]?print|working[ -]?paper|discussion[ -]?paper|policy[ -]?brief|"
    r"press[ -]?release|government[ -]?report|white[ -]?paper|news(?:letter)?|blog)\b",
    re.IGNORECASE,
)
_CHROME_TITLE_RE = re.compile(
    r"^(?:just a moment|error\b|access denied|page not found|cookies? (?:are )?(?:disabled|turned off))",
    re.IGNORECASE,
)
_DOI_RE = re.compile(r"\b(10\.\d{4,9})/[\w.()/:+-]+", re.IGNORECASE)

# Generic article-route shapes used by journal platforms.  No venue or task names are encoded.
_JOURNAL_ARTICLE_URL_RES = tuple(re.compile(pattern, re.IGNORECASE) for pattern in (
    r"/articles/pmc\d+/?$",
    r"/science/article/pii/",
    r"/journals?/[^?#]*/articles?/",
    r"/article/10\.\d{4,9}/",
    r"/doi/(?:abs/|full/|pdf/|epdf/)?10\.\d{4,9}/",
    r"/core/journals/[^/]+/article/",
    r"/(?:ojs/)?index\.php/[^/]+/article/(?:view|download)/",
    r"/article/\d+/\d+/",
    r"/article/(?:view|download)/\d+",
    r"/content/\d+/\d+/",
))
_JOURNAL_HOST_LABEL_RE = re.compile(r"^(?:journal|journals)[.-]", re.IGNORECASE)
_JOURNAL_VENUE_RE = re.compile(r"\b(?:journal|review|quarterly)\b", re.IGNORECASE)
_VOLUME_ISSUE_RE = re.compile(
    r"\b(?:vol(?:ume)?\.?\s*\d+\s*[,;:]?\s*(?:no\.?|issue)\s*\d+|\d+\s*\(\s*\d+\s*\))\b",
    re.IGNORECASE,
)


@dataclass
class CitationEligibilityPlan:
    active: bool = False
    body_evidence: list[dict[str, Any]] = field(default_factory=list)
    disclosed_evidence: list[dict[str, Any]] = field(default_factory=list)
    backfills: list[dict[str, str]] = field(default_factory=list)


def enabled() -> bool:
    return (resolve("PG_EXCLUSIVE_CITATION_ELIGIBILITY") or "").strip().lower() not in _OFF


def has_explicit_exclusive_constraint(prompt: str, constraints: Mapping[str, Any] | None) -> bool:
    if not constraints or not _EXCLUSIVE_RE.search(prompt or ""):
        return False
    return bool(
        constraints.get("source_types")
        or constraints.get("languages")
        or constraints.get("recency")
        or constraints.get("exclusions")
    )


def _host(row: Mapping[str, Any]) -> str:
    url = str(row.get("source_url") or row.get("url") or "")
    try:
        return (urlsplit(url).hostname or "").lower()
    except ValueError:
        return ""


def _host_in(host: str, choices: frozenset[str]) -> bool:
    return any(host == item or host.endswith("." + item) for item in choices)


def known_non_journal_surface(row: Mapping[str, Any]) -> bool:
    """Return True only for an affirmative offline non-journal surface signal."""
    host = _host(row)
    if _host_in(host, _NON_JOURNAL_HOSTS):
        return True
    text = " ".join(str(row.get(key) or "") for key in (
        "title", "source_url", "url", "source_class", "document_type",
    ))
    if _NON_JOURNAL_TEXT_RE.search(text):
        return True
    doi_match = _DOI_RE.search(" ".join(str(row.get(key) or "") for key in (
        "doi", "source_url", "url",
    )))
    return bool(doi_match and doi_match.group(1).lower() in _NON_JOURNAL_DOI_REGISTRANTS)


def known_preprint_or_working_paper_host(row: Mapping[str, Any]) -> bool:
    """Return True for a recognized preprint/repository/working-paper hostname."""
    return _host_in(_host(row), _PREPRINT_OR_WORKING_PAPER_HOSTS)


def _unknown_row_has_journal_signal(row: Mapping[str, Any]) -> bool:
    """Conservative positive classifier for otherwise-UNKNOWN rows; pure and offline."""
    if known_non_journal_surface(row):
        return False
    title = str(row.get("title") or "").strip()
    if not title or _CHROME_TITLE_RE.search(title):
        return False
    url = str(row.get("source_url") or row.get("url") or "")
    host = _host(row)

    # A resolvable DOI is affirmative publication metadata unless its registrant/surface is one of
    # the explicit repository and working-paper classes vetoed above.
    if _DOI_RE.search(" ".join((str(row.get("doi") or ""), url))):
        return True
    if any(pattern.search(url) for pattern in _JOURNAL_ARTICLE_URL_RES):
        return True
    if _JOURNAL_HOST_LABEL_RE.search(host + ".") and "/article" in url.lower():
        return True

    venue = " ".join(str(row.get(key) or "") for key in ("journal", "venue"))
    publication = " ".join((title, venue, str(row.get("citation") or "")))
    return bool(
        _JOURNAL_VENUE_RE.search(venue)
        and _VOLUME_ISSUE_RE.search(publication)
    )


def _eligible(row: Mapping[str, Any], constraints: Mapping[str, Any]) -> tuple[bool, list[str]]:
    reasons: list[str] = []
    source_types = [str(item) for item in constraints.get("source_types", [])]
    admitted = _admitted_genres(source_types)
    if admitted is not None:
        genre = _row_genre(row)
        if genre == DocumentType.UNKNOWN and row.get("document_type"):
            try:
                genre = DocumentType(str(row.get("document_type")).strip().upper())
            except ValueError:
                pass
        if genre == DocumentType.UNKNOWN and _unknown_row_has_journal_signal(row):
            genre = DocumentType.JOURNAL_ARTICLE
        if admitted.issubset({DocumentType.JOURNAL_ARTICLE, DocumentType.REVIEW_ARTICLE}) \
                and known_non_journal_surface(row):
            # An explicit repository/working-paper/conference/dataset surface wins even over a
            # stale positive document_type stamp.  The published manifestation can still enter via
            # the same-work replacement path below; the non-journal manifestation cannot be cited.
            genre = DocumentType.PREPRINT
        if genre not in admitted:
            reasons.append("document_type")
    languages = [str(item).strip().lower()[:2] for item in constraints.get("languages", [])]
    if languages:
        language = _row_language(row)
        if language is None:
            language = detect_language_offline(" ".join(
                str(row.get(key) or "")
                for key in ("title", "snippet", "abstract", "statement", "direct_quote")
            ))
        # Missing/ambiguous language metadata is not evidence of a mismatch.  Reject only a
        # positively identified language outside the explicit allow-set.
        if language is not None and language not in languages:
            reasons.append("language")
    floor, ceiling = _parse_recency_bounds(constraints.get("recency"))
    if floor is not None or ceiling is not None:
        year = _row_year(row)
        if year is None or (floor is not None and year < floor) or (ceiling is not None and year > ceiling):
            reasons.append("recency")
    return not reasons, reasons


def _group_members(
    groups: Sequence[Mapping[str, Any]] | None,
    rows: Sequence[Mapping[str, Any]],
) -> dict[str, set[str]]:
    by_member: dict[str, set[str]] = {}
    for group in groups or []:
        members = {str(item) for item in group.get("member_evidence_ids", []) if str(item)}
        for member in members:
            by_member.setdefault(member, set()).update(members)
    # Composition rows can carry the same resolver result inline after canonicalization.  Consult
    # that representation too, rather than depending on the optional top-level group payload.
    for row in rows:
        evidence_id = str(row.get("evidence_id") or "")
        members = {
            str(item)
            for item in row.get("same_work_member_evidence_ids", []) or []
            if str(item)
        }
        if evidence_id:
            members.add(evidence_id)
        if len(members) > 1:
            for member in members:
                by_member.setdefault(member, set()).update(members)
    return by_member


def _title_key(row: Mapping[str, Any]) -> str:
    return re.sub(r"[^\w]+", " ", str(row.get("title") or "").casefold()).strip()


def plan_citation_eligibility(
    *,
    prompt: str,
    constraints: Mapping[str, Any] | None,
    evidence: Sequence[Mapping[str, Any]],
    same_work_groups: Sequence[Mapping[str, Any]] | None = None,
) -> CitationEligibilityPlan:
    original = [dict(row) for row in evidence]
    if not enabled() or not has_explicit_exclusive_constraint(prompt, constraints):
        return CitationEligibilityPlan(active=False, body_evidence=original)
    rules = dict(constraints or {})
    rows_by_id = {str(row.get("evidence_id") or ""): row for row in original}
    eligible_ids = {
        evidence_id for evidence_id, row in rows_by_id.items()
        if evidence_id and _eligible(row, rules)[0]
    }
    member_groups = _group_members(same_work_groups, original)
    eligible_by_title: dict[str, str] = {}
    for evidence_id in eligible_ids:
        key = _title_key(rows_by_id[evidence_id])
        if key:
            eligible_by_title.setdefault(key, evidence_id)

    selected: list[dict[str, Any]] = []
    selected_ids: set[str] = set()
    disclosed: list[dict[str, Any]] = []
    backfills: list[dict[str, str]] = []
    for row in original:
        evidence_id = str(row.get("evidence_id") or "")
        ok, reasons = _eligible(row, rules)
        replacement = ""
        if not ok:
            candidates = member_groups.get(evidence_id, set())
            replacement = next((item for item in sorted(candidates) if item in eligible_ids), "")
            if not replacement:
                replacement = eligible_by_title.get(_title_key(row), "")
        chosen_id = evidence_id if ok else replacement
        if chosen_id and chosen_id not in selected_ids and chosen_id in rows_by_id:
            selected.append(dict(rows_by_id[chosen_id]))
            selected_ids.add(chosen_id)
        if not ok:
            disclosed.append({
                "evidence_id": evidence_id,
                "title": str(row.get("title") or ""),
                "source_url": str(row.get("source_url") or row.get("url") or ""),
                "reasons": reasons,
                "statement": str(row.get("statement") or row.get("direct_quote") or ""),
                "eligible_same_work_evidence_id": replacement or None,
            })
            if replacement:
                backfills.append({"from_evidence_id": evidence_id, "to_evidence_id": replacement})
    logger.info(
        "[citation_eligibility] admitted=%d disclosed=%d backfilled=%d retained_corpus=%d",
        len(selected), len(disclosed), len(backfills), len(original),
    )
    return CitationEligibilityPlan(
        active=True,
        body_evidence=selected,
        disclosed_evidence=disclosed,
        backfills=backfills,
    )
